SELECT DISTINCT customer_id
FROM customers_raw
ORDER BY customer_id;

SELECT COUNT(*) AS null_phone_count
FROM customers_raw
WHERE phone IS NULL;

SELECT DISTINCT customer_segment
FROM customers_raw
ORDER BY customer_segment;

SELECT COUNT(*) AS k_income_count
FROM customers_raw
WHERE income ILIKE '%K%';

SELECT COUNT(*) AS null_purchase_date
FROM customers_raw
WHERE last_purchase_date IS NULL;

SELECT DISTINCT state
FROM customers_raw
ORDER BY state;

SELECT *
FROM customers_raw
LIMIT 5;

SELECT column_name, data_type
FROM information_schema.columns
WHERE table_name = 'customers_raw';

SELECT MIN(customer_id) AS min_id,
       MAX(customer_id) AS max_id
FROM customers_raw;

SELECT COUNT(*) AS active_count
FROM customers_raw
WHERE LOWER(is_active) = 'yes';

SELECT *
FROM customers_raw
WHERE registration_date LIKE '2020%';

DELETE FROM customers_raw
WHERE ctid NOT IN (
  SELECT MIN(ctid)
  FROM customers_raw
  GROUP BY customer_id
);

DELETE FROM customers_raw
WHERE ctid NOT IN (
  SELECT MAX(ctid)
  FROM customers_raw
  GROUP BY customer_id
);

WITH cte AS (
  SELECT ctid,
    ROW_NUMBER() OVER (
      PARTITION BY customer_id
      ORDER BY ctid
    ) AS rn
  FROM customers_raw
)
DELETE FROM customers_raw
WHERE ctid IN (
  SELECT ctid FROM cte WHERE rn > 1
);

SELECT DISTINCT ON (customer_id) *
FROM customers_raw
ORDER BY customer_id, ctid;

SELECT * FROM customers_raw
WHERE customer_id IN (
  SELECT customer_id FROM customers_raw
  GROUP BY customer_id HAVING COUNT(*) > 1
)
ORDER BY customer_id, ctid;

WITH cte AS (
  SELECT ctid,
    ROW_NUMBER() OVER(
      PARTITION BY customer_id
      ORDER BY ctid
    ) AS rn
  FROM customers_raw
)
DELETE FROM customers_raw
WHERE ctid IN (SELECT ctid FROM cte WHERE rn > 1);

UPDATE customers_raw
SET notes = LTRIM(notes)
WHERE notes IS NOT NULL;

UPDATE customers_raw
SET notes = RTRIM(notes)
WHERE notes IS NOT NULL;

UPDATE customers_raw
SET email = LOWER(TRIM(email))
WHERE email IS NOT NULL;

UPDATE customers_raw
SET first_name = INITCAP(TRIM(first_name))
WHERE first_name IS NOT NULL;

UPDATE customers_raw
SET last_name = INITCAP(TRIM(last_name))
WHERE last_name IS NOT NULL;

UPDATE customers_raw
SET address = REGEXP_REPLACE(TRIM(address), '\s+', ' ', 'g')
WHERE address IS NOT NULL;

SELECT phone,
  REGEXP_REPLACE(phone, '[^0-9]', '', 'g') AS digits_only
FROM customers_raw;

UPDATE customers_raw
SET phone = REPLACE(phone, '.', '-')
WHERE phone LIKE '%.%';

UPDATE customers_raw
SET email = REPLACE(email, ' ', '')
WHERE email LIKE '% %';

UPDATE customers_raw
SET customer_segment = TRIM(customer_segment)
WHERE customer_segment != TRIM(COALESCE(customer_segment,''));

UPDATE customers_raw
SET state = UPPER(TRIM(state))
WHERE state IS NOT NULL;

UPDATE customers_raw
SET city = INITCAP(LOWER(TRIM(city)))
WHERE city IS NOT NULL;

UPDATE customers_raw
SET notes = NULL
WHERE TRIM(notes) = '';

UPDATE customers_raw
SET phone = REPLACE(phone, ' ', '')
WHERE phone LIKE '% %';

UPDATE customers_raw
SET notes = RTRIM(notes)
WHERE notes ILIKE '%Needs attention%';

UPDATE customers_raw
SET is_active = 'Yes'
WHERE LOWER(is_active) = 'yes';

UPDATE customers_raw
SET is_active = 'Yes'
WHERE is_active = 'Y';

UPDATE customers_raw
SET is_active = 'No'
WHERE is_active = 'N';

UPDATE customers_raw
SET customer_segment = NULL
WHERE customer_segment = 'Invalid';

SELECT zip_code,
  LPAD(REGEXP_REPLACE(zip_code,'[^0-9]','','g'), 5, '0') AS clean_zip
FROM customers_raw;

SELECT TO_DATE('06/15/1990', 'MM/DD/YYYY') AS iso_date;
-- For the table:
SELECT customer_id,
  TO_DATE(birth_date, 'MM/DD/YYYY') AS fixed_date
FROM customers_raw
WHERE birth_date ~ '^\d{2}/\d{2}/\d{4}$';

SELECT * FROM customers_raw
WHERE birth_date ~ '^\d{4}-\d{2}-\d{2}$'
  AND (
    SPLIT_PART(birth_date,'-',2)::INT NOT BETWEEN 1 AND 12
    OR SPLIT_PART(birth_date,'-',3)::INT NOT BETWEEN 1 AND 31
  );

SELECT * FROM customers_raw
WHERE birth_date IS NOT NULL
  AND birth_date !~ '^\d{4}-\d{2}-\d{2}$';

SELECT first_name, birth_date,
  EXTRACT(YEAR FROM
    AGE(CURRENT_DATE, TO_DATE(birth_date,'YYYY-MM-DD'))
  )::INT AS calculated_age
FROM customers_raw
WHERE birth_date ~ '^\d{4}-\d{2}-\d{2}$';

SELECT customer_id, first_name, last_name
FROM customers_raw
WHERE last_purchase_date IS NULL;

SELECT * FROM customers_raw
WHERE birth_date ~ '^\d{4}-\d{2}-\d{2}$'
  AND TO_DATE(birth_date,'YYYY-MM-DD') > CURRENT_DATE;

SELECT * FROM customers_raw
WHERE birth_date ~ '^\d{4}-\d{2}-\d{2}$'
  AND birth_date < '1980-01-01';

SELECT ROUND(AVG(
  EXTRACT(YEAR FROM AGE(TO_DATE(birth_date,'YYYY-MM-DD')))
), 1) AS avg_age
FROM customers_raw
WHERE birth_date ~ '^\d{4}-\d{2}-\d{2}$';

UPDATE customers_raw
SET income = ((REPLACE(UPPER(income),'K',''))::NUMERIC * 1000)::TEXT
WHERE income ILIKE '%K';

UPDATE customers_raw
SET income = NULL
WHERE income ~ '^-[0-9]+';

UPDATE customers_raw
SET total_purchases = '0'
WHERE total_purchases ~ '^-[0-9]+$';

UPDATE customers_raw
SET total_purchases = '0'
WHERE total_purchases IS NULL;

SELECT * FROM customers_raw
WHERE income ~ '^[0-9]+$'
  AND income::NUMERIC > 100000;

SELECT MIN(income::NUMERIC) AS min_income
FROM customers_raw
WHERE income ~ '^[0-9]+$';

SELECT MAX(income::NUMERIC) AS max_income
FROM customers_raw
WHERE income ~ '^[0-9]+$';

SELECT ROUND(AVG(total_purchases::NUMERIC), 2) AS avg_purchases
FROM customers_raw
WHERE total_purchases ~ '^[0-9]+$';

SELECT * FROM customers_raw
WHERE total_purchases ~ '^[0-9]+$'
  AND total_purchases::INT > 20;

SELECT SUM(total_purchases::NUMERIC) AS grand_total
FROM customers_raw
WHERE total_purchases ~ '^[0-9]+$';

SELECT * FROM customers_raw
WHERE income ~ '^[0-9]+$'
  AND ABS(income::NUMERIC - (
    SELECT AVG(income::NUMERIC) FROM customers_raw WHERE income ~ '^[0-9]+$'
  )) > 2 * (
    SELECT STDDEV(income::NUMERIC) FROM customers_raw WHERE income ~ '^[0-9]+$'
  );

SELECT * FROM customers_raw
WHERE total_purchases IS NOT NULL
  AND total_purchases !~ '^-?[0-9]+$';

UPDATE customers_raw
SET total_purchases = '0'
WHERE TRIM(COALESCE(total_purchases,'')) = '';

SELECT * FROM customers_raw
WHERE age ~ '^[0-9]+$'
  AND (age::INT < 0 OR age::INT > 120);

UPDATE customers_raw
