SELECT * FROM customers_raw
WHERE phone IS NOT NULL
  AND LENGTH(REGEXP_REPLACE(phone,'[^0-9]','','g')) != 10;

SELECT * FROM customers_raw
WHERE zip_code IS NOT NULL
  AND zip_code !~ '^[0-9]{5}$';

SELECT * FROM customers_raw
WHERE age ~ '^[0-9]+$'
  AND (age::INT < 18 OR age::INT > 100);

SELECT DISTINCT is_active FROM customers_raw
WHERE LOWER(COALESCE(is_active,'')) NOT IN
  ('yes','no','true','false','y','n','1','0');

SELECT * FROM customers_raw
WHERE phone IS NOT NULL
  AND phone !~ '^(\(\d{3}\)|\d{3})[\s.\-]?\d{3}[.\-]?\d{4}$';

SELECT * FROM customers_raw
WHERE birth_date ~ '^\d{4}-\d{2}-\d{2}$'
  AND TO_DATE(birth_date,'YYYY-MM-DD') >= CURRENT_DATE;

SELECT * FROM customers_raw
WHERE zip_code IS NOT NULL
  AND LENGTH(TRIM(zip_code)) != 5;

SELECT DISTINCT customer_segment
FROM customers_raw
WHERE customer_segment != INITCAP(LOWER(customer_segment));

SELECT * FROM customers_raw
WHERE email != LOWER(email)
  AND email IS NOT NULL;

SELECT * FROM customers_raw
WHERE (first_name IS NULL OR TRIM(first_name) = '')
  AND (last_name  IS NULL OR TRIM(last_name)  = '');

SELECT * FROM customers_raw
WHERE registration_date ~ '^\d{4}-\d{2}-\d{2}$'
  AND (
    EXTRACT(YEAR FROM TO_DATE(registration_date,'YYYY-MM-DD')) < 2015
    OR EXTRACT(YEAR FROM TO_DATE(registration_date,'YYYY-MM-DD')) > 2026
  );

ALTER TABLE customers_raw ADD COLUMN IF NOT EXISTS full_name VARCHAR(200);
UPDATE customers_raw
SET full_name = INITCAP(TRIM(COALESCE(first_name,''))) || ' '
  || INITCAP(TRIM(COALESCE(last_name,'')));

ALTER TABLE customers_raw ADD COLUMN IF NOT EXISTS is_active_bool BOOLEAN;
UPDATE customers_raw
SET is_active_bool = CASE
  WHEN LOWER(is_active) IN ('yes','true','y','1') THEN TRUE
  ELSE FALSE
END;

join_questions.sol:
SELECT e.emp_name, d.dept_name
FROM employees e
INNER JOIN departments d ON e.dept_id = d.dept_id;

SELECT e.emp_name, e.salary, d.dept_name
FROM employees e
JOIN departments d ON e.dept_id = d.dept_id;

SELECT e.emp_name, d.dept_name
FROM employees e
FULL OUTER JOIN departments d ON e.dept_id = d.dept_id;

SELECT e.emp_name, d.dept_name, d.location
FROM employees e
JOIN departments d ON e.dept_id = d.dept_id;

SELECT emp_name
FROM employees
WHERE manager_id IS NULL;

SELECT e.emp_name, d.dept_name
FROM employees e
JOIN departments d ON e.dept_id = d.dept_id
WHERE d.dept_id IN (
  SELECT dept_id FROM employees GROUP BY dept_id HAVING COUNT(*) = 1
);
